using System.ComponentModel;
using System.Net;
using System.Text.Json;

namespace ResearchAgent;

/// <summary>
/// Simulates web search results. Replace the body of <see cref="SearchAsync"/>
/// with a real search API (e.g., Bing Search, Google Custom Search) for production use.
/// </summary>
public static class WebSearchTool
{
    private static readonly HttpClient HttpClient = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
        Timeout = TimeSpan.FromSeconds(10),
    };

    public static async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        // Simulated search results keyed by topic keywords.
        // In production, call a real search API here.
        var results = GenerateSimulatedResults(query);

        var json = JsonSerializer.Serialize(results, new JsonSerializerOptions
        {
            WriteIndented = true,
        });

        return json;
    }

    private static List<SearchResult> GenerateSimulatedResults(string query)
    {
        var q = query.ToLowerInvariant();

        if (q.Contains("climate") || q.Contains("global warming"))
        {
            return
            [
                new("NASA Climate Change Evidence",
                    "Global temperature has risen about 1.1°C since the late 1800s. "
                    + "The ocean has absorbed much of this increased heat, with the top 100 meters warming more than 0.33°C since 1969. "
                    + "Ice sheets in Greenland and Antarctica have decreased in mass.",
                    "https://climate.nasa.gov/evidence/"),
                new("IPCC Sixth Assessment Report Summary",
                    "Human influence has warmed the climate at a rate unprecedented in at least the last 2000 years. "
                    + "Global surface temperature reached 1.1°C above 1850-1900 in 2011-2020. "
                    + "Each of the last four decades has been successively warmer than any preceding decade since 1850.",
                    "https://www.ipcc.ch/report/ar6/"),
                new("Effects of Climate Change - National Geographic",
                    "Rising seas, increased wildfires, more intense hurricanes, and shifting ecosystems are among the effects. "
                    + "Arctic sea ice is declining at 13% per decade. Coral reefs face bleaching events with 1.5°C warming.",
                    "https://www.nationalgeographic.com/environment/climate-change/"),
            ];
        }

        if (q.Contains("artificial intelligence") || q.Contains(" ai ") || q.Contains("machine learning"))
        {
            return
