using System.ComponentModel;
using System.Text;

namespace ResearchAgent;

/// <summary>
/// A simple in-memory notebook that the agent uses to collect research findings.
/// </summary>
public sealed class Notebook
{
    private readonly List<Note> _notes = [];

    public string AddNote(
        [Description("A short title for this note")] string title,
        [Description("The detailed content of the note")] string body)
    {
        var note = new Note(title, body, DateTime.UtcNow);
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    public string ReadNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===\n");

        for (var i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            sb.AppendLine($"--- Note #{i + 1}: {note.Title} ---");
            sb.AppendLine(note.Body);
            sb.AppendLine();
        }

        Console.WriteLine($"  📖 Reading {_notes.Count} notes");
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();

    private record Note(string Title, string Body, DateTime CreatedAt);
}

